To expand upon the previous Python text-based game example with separate control for left and right doors, a light mechanism, and the chance for Freddy to attack if the power goes out, we'll make several modifications to the game logic. Here is a sample implementation:

```python
import random
import time

# Initial states
power = 100
nights = 1
animatronics = {
    'Freddy': {'location': 'Show Stage', 'is_active': False},
    'Chica': {'location': 'Show Stage', 'is_active': False},
    'Bonnie': {'location': 'Show Stage', 'is_active': False},
    'Foxy': {'location': 'Pirate Cove', 'is_active': False}
}

# Left and right doors represented as dictionaries that track the status and power drain.
doors = {
    'left': {'is_closed': False, 'name': 'Left Door'},
    'right': {'is_closed': False, 'name': 'Right Door'}
}

# Main functions
def check_cameras(power_usage):
    global power
    print("\nYou check the cameras...")
    for name, animatronic in animatronics.items():
        if animatronic['is_active']:
            print(f"You spot {name} at the {animatronic['location']}.")
    power -= power_usage

def check_power():
    return power > 0

def print_status():
    print(f"\nNight {nights}. Power: {power}%")
    for door_side in doors:
        state = "closed" if doors[door_side]['is_closed'] else "open"
        print(f"The {doors[door_side]['name']} is {state}.")

def manage_door(door_side):
    global power
    door = doors[door_side]
    if not door['is_closed']:
        door['is_closed'] = True
        print(f"You close the {door['name']}.")
    else:
        door['is_closed'] = False
        print(f"You open the {door['name']}.")

def use_lights(door_side, power_usage):
    global power
    door = doors[door_side]
    state = "closed" if door['is_closed'] else "open"
    print(f"You turn on the lights near the {door['name']}. The door is {state}.")
    # Implement logic to check if animatronics are close to the doors
    for name, animatronic in animatronics.items():
        if door['name'].startswith(animatronic['location']):
            print(f"{name} is near the {door['name']}!")
    power -= power_usage

# Setup for each night
def setup_night():
    global power, nights
    print("\n--------------------------------")
    print(f"Night {nights}")
    print("--------------------------------")
    # Probability of being active increases each night
    for name in animatronics:
        animatronics[name]['is_active'] = random.randint(0, nights) < nights

# Main game loop
is_alive = True
print("Welcome to Five Nights at Freddy's: Text Edition!")

while is_alive and nights <= 5:
    setup_night()

    while check_power() and is_alive:
        print_status()

        print("\nWhat would you like to do?")
        print("1. Check cameras")
        print("2. Close left door")
        print("3. Close right door")
        print("4. Open left door")
        print("5. Open right door")
        print("6. Lights on left door")
        print("7. Lights on right door")
        print("8. Do nothing")

        action = input("> ").strip()

        if action == '1':
            check_cameras(5)
        elif action == '2':
            manage_door('left')
        elif action == '3':
            manage_door('right')
        elif action == '4':
            manage_door('left')
        elif action == '5':
            manage_door('right')
        elif action == '6':
            use_lights('left', 2)
        elif action == '7':
            use_lights('right', 2)
        elif action == '8':
            print("You wait and conserve power.")
        else:
            print("Invalid action. Please choose from the given options.")

        if random.choice([True, False]):  # Random move for the animatronics.
            print("You hear some movement...")

        power -= 1 + doors['left']['is_closed'] + doors['right']['is_closed']  # Power drain

        if power <= 0:
            print("\nThe power has gone out...")
            is_alive = random.randint(0, 100) >= 90  # Freddy has a 10% chance of attacking when the power goes out
            if not is_alive:
                print("\nFreddy found you in the dark... GAME OVER.")

        time.sleep(1)

    if is_alive:
        print("\nYou survived the night!\n")
        nights += 1
        power = 100
    else:
        print("\nYou didn't make it through the night.")

if is_alive:
    print("Congratulations, you survived Five Nights at Freddy's!")
else:
    print("GAME OVER")
```

This updated code now includes separate left and right doors that can be independently opened and closed. We introduced a light mechanism that allows the player to check near the doors for approaching animatronics, though in this limited text-based game, it's a simplified system. When the power goes out, Freddy now has a chance of attacking you — this is only a 10% chance for the purposes of this example, but this can be adjusted to fit the desired difficulty of the game.

Due to platform limitations, this example remains quite basic compared to a real-life full-scale game and only serves as an illustrative snippet. As before, full-scale game development would involve more advanced programming concepts, better game state management (possibly with Object-Oriented Programming), and robust systems for handling differing scenarios.
